public class InterfaceConstants {
    interface Config {
        int MAX = 100;       // implicitly public static final
        String VERSION = "1.0";
    }
    static class App implements Config {
        void show() { System.out.println(MAX + " " + VERSION); }
    }
    public static void main(String[] args) {
        App app = new App();
        app.show();
        System.out.println(Config.MAX);
        System.out.println(app.MAX);
    }
}
